"use client";

import { motion } from "framer-motion";
import { Users, Award, Briefcase, Calendar } from "lucide-react";

const stats = [
    {
        label: "Clients Worked With",
        value: "50+",
        icon: Users,
        color: "from-blue-500/20 to-indigo-500/20",
    },
    {
        label: "Certifications",
        value: "27+",
        icon: Award,
        color: "from-purple-500/20 to-pink-500/20",
    },
    {
        label: "Products Built",
        value: "Multiple",
        icon: Briefcase,
        color: "from-orange-500/20 to-red-500/20",
    },
    {
        label: "Years Experience",
        value: "5+",
        icon: Calendar,
        color: "from-emerald-500/20 to-teal-500/20",
    },
];

export default function About() {
    return (
        <section id="about" className="py-24 px-6 relative overflow-hidden">
            <div className="container mx-auto max-w-6xl section-reveal">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-16 items-center">
                    <div className="space-y-6">
                        <h2 className="text-4xl md:text-5xl font-bold tracking-tight text-white animate-fade-in">
                            The Startup <span className="gradient-text">Generalist</span>.
                        </h2>
                        <div className="space-y-4 text-muted text-lg leading-relaxed">
                            <p>
                                Dev Chopra is a product-minded builder with experience across marketing, operations,
                                design, AI tools, and startup growth.
                            </p>
                            <p>
                                He has worked with 50+ global clients, built digital products and marketing systems,
                                and focuses on execution and experimentation.
                            </p>
                            <p>
                                Switching between marketing, product and code when required, he brings high agency
                                execution to every project.
                            </p>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        {stats.map((stat, index) => (
                            <motion.div
                                key={index}
                                whileHover={{ y: -10 }}
                                className="p-6 glass border border-white/5 rounded-2xl flex flex-col space-y-4 relative group"
                            >
                                <div className={`absolute inset-0 bg-gradient-to-br ${stat.color} opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-2xl -z-10`} />
                                <div className="w-12 h-12 rounded-xl glass border border-white/10 flex items-center justify-center mb-2">
                                    <stat.icon className="w-6 h-6 text-white" />
                                </div>
                                <div className="text-3xl font-bold text-white">{stat.value}</div>
                                <div className="text-sm text-muted uppercase tracking-wider">{stat.label}</div>
                            </motion.div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Decorative Blob */}
            <div className="absolute top-1/2 -right-1/4 w-[400px] h-[400px] bg-purple-500/10 rounded-full blur-[100px] -z-10" />
        </section>
    );
}
